from __future__ import annotations
import json
from pathlib import Path
HTML=Path('docs/index.html');DATA=Path('data/dashboard/wnba_market_intelligence.json')
CSS=r'''<style id="v4-market-intelligence-style">.miGrid{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:12px}.miCard{border:1px solid #21314b;border-radius:14px;padding:14px;background:#0a1322}.miValue{font-size:26px;font-weight:950}.miTable{width:100%;border-collapse:collapse;margin-top:12px}.miTable th,.miTable td{padding:8px;border-bottom:1px solid #1d2b42;text-align:left;font-size:12px}.miPos{color:#00e39b}.miNeg{color:#ff6b7c}.miStable{color:#8fa0bd}.miTimeline{margin-top:8px;padding-top:8px;border-top:1px solid #20304b}.miPoint{font-size:10px;color:#8fa0bd;padding:3px 0}</style>'''
SCRIPT=r'''<script id="v4-market-intelligence-script">(function(){window.marketIntelligence=function(){const p=DATA.market_intelligence||{},s=p.summary||{},rows=Array.isArray(p.records)?p.records:[];const cards=rows.slice(0,12).map(r=>{const cls=Number(r.line_clv)>0?'miPos':Number(r.line_clv)<0?'miNeg':'miStable';const timeline=(r.timeline||[]).map(t=>`<div class="miPoint mono">${E(t.stage)} · ${E(t.line)} (${E(t.odds)}) · ${E(t.sportsbook||'—')}</div>`).join('');return `<div class="miCard"><b>${E(r.player||r.game||'Market')} ${E(r.side)} ${E(r.recommendation_line)} ${E(r.stat)}</b><div class="small mono">${E(r.sportsbook||'—')} · ${E(r.model_version)}</div><div class="row"><span class="${cls} mono">CLV ${Number(r.line_clv)>=0?'+':''}${E(r.line_clv)}</span><span class="mono">Efficiency ${E(r.market_efficiency_score)}</span></div><div class="small mono">Open ${E(r.opening_line)} → Rec ${E(r.recommendation_line)} → Close ${E(r.closing_line)}</div><div class="small">${E(r.movement_classification)}</div><div class="miTimeline">${timeline}</div></div>`}).join('');const statRows=(p.by_stat||[]).slice(0,12).map(r=>`<tr><td>${E(r.group)}</td><td>${E(r.count)}</td><td>${r.average_line_clv==null?'—':E(r.average_line_clv)}</td><td>${r.positive_clv_rate==null?'—':(Number(r.positive_clv_rate)*100).toFixed(1)+'%'}</td><td>${r.roi==null?'—':(Number(r.roi)*100).toFixed(1)+'%'}</td></tr>`).join('');return `<div class="section"><h2 class="mono">Closing Line Value & Market Movement</h2><div class="small mono">Immutable opening, recommendation, intermediate, and closing observations. Positive CLV means the model captured a better number than the close.</div><div class="miGrid"><div class="miCard"><div class="small">Tracked</div><div class="miValue mono">${E(s.tracked_markets||0)}</div></div><div class="miCard"><div class="small">Average CLV</div><div class="miValue mono">${s.average_line_clv==null?'—':E(s.average_line_clv)}</div></div><div class="miCard"><div class="small">Positive CLV</div><div class="miValue mono">${s.positive_clv_rate==null?'—':(Number(s.positive_clv_rate)*100).toFixed(1)+'%'}</div></div><div class="miCard"><div class="small">Beat Close</div><div class="miValue mono">${s.beat_close_rate==null?'—':(Number(s.beat_close_rate)*100).toFixed(1)+'%'}</div></div><div class="miCard"><div class="small">Market Efficiency</div><div class="miValue mono">${s.average_market_efficiency_score==null?'—':E(s.average_market_efficiency_score)}</div></div></div><div class="miGrid">${cards||'<div class="empty mono">Market history will populate as scheduled observations accumulate.</div>'}</div><table class="miTable"><thead><tr><th>Stat</th><th>N</th><th>Avg CLV</th><th>Positive</th><th>ROI</th></tr></thead><tbody>${statRows||'<tr><td colspan="5">No historical CLV yet.</td></tr>'}</tbody></table></div>`};const previous=window.fullGamePerformance;window.fullGamePerformance=function(){const base=typeof previous==='function'?previous():'';return base+window.marketIntelligence()};})();</script>'''
def replace_block(html,start,end,replacement):
 i=html.find(start)
 if i<0:return html
 j=html.find(end,i)
 if j<0:return html
 return html[:i]+replacement.strip()+html[j+len(end):]
def main():
 if not HTML.exists():raise SystemExit('docs/index.html missing')
 try:payload=json.load(DATA.open(encoding='utf-8')) if DATA.exists() else {}
 except Exception:payload={}
 html=HTML.read_text(encoding='utf-8');data=f'<script id="v4-market-intelligence-data">DATA.market_intelligence={json.dumps(payload,separators=(",",":"),ensure_ascii=False)};</script>'
 html=replace_block(html,'<script id="v4-market-intelligence-data">','</script>',data) if 'id="v4-market-intelligence-data"' in html else html.replace('</body>',data+'</body>')
 html=replace_block(html,'<style id="v4-market-intelligence-style">','</style>',CSS) if 'id="v4-market-intelligence-style"' in html else html.replace('</head>',CSS+'</head>')
 html=replace_block(html,'<script id="v4-market-intelligence-script">','</script>',SCRIPT) if 'id="v4-market-intelligence-script"' in html else html.replace('</body>',SCRIPT+'</body>')
 HTML.write_text(html,encoding='utf-8');print('CLV and Market Movement added to Performance Center')
if __name__=='__main__':main()
